class Solution:
    def earliestSecondToMarkIndices(self, nums, changeIndices):
        import heapq
        n, m = len(nums), len(changeIndices)
        total = sum(nums)
        def feasible(T):
            last = {}
            for s in range(T):
                last[changeIndices[s]] = s
            h = []
            free = 0
            total_saved = 0
            for s in range(T - 1, -1, -1):
                idx = changeIndices[s]
                if last.get(idx) == s:
                    heapq.heappush(h, -nums[idx - 1])
                    top = -h[0]
                    if top > 1:
                        total_saved += top
                        heapq.heappop(h)
                    else:
                        heapq.heappop(h)
                        free += 1
                else:
                    free += 1
            return free >= (total - total_saved) + n
        for T in range(1, m + 1):
            if feasible(T):
                return T
        return -1

