var earliestSecondToMarkIndices = function(nums, changeIndices) {
    const n = nums.length, m = changeIndices.length;
    const totalNums = nums.reduce((a, b) => a + b, 0);
    // Max-heap via min-heap with negation
    function heapPush(h, v) {
        h.push(v);
        let i = h.length - 1;
        while (i > 0) {
            const p = (i - 1) >> 1;
            if (h[p] <= h[i]) break;
            [h[p], h[i]] = [h[i], h[p]]; i = p;
        }
    }
    function heapPop(h) {
        const top = h[0], last = h.pop();
        if (h.length > 0) {
            h[0] = last;
            let i = 0;
            while (true) {
                let s = i, l = 2*i+1, r = 2*i+2;
                if (l < h.length && h[l] < h[s]) s = l;
                if (r < h.length && h[r] < h[s]) s = r;
                if (s === i) break;
                [h[s], h[i]] = [h[i], h[s]]; i = s;
            }
        }
        return top;
    }
    function feasible(T) {
        const last = new Map();
        for (let s = 0; s < T; s++) last.set(changeIndices[s], s);
        const h = [];
        let free = 0, saved = 0;
        for (let s = T - 1; s >= 0; s--) {
            const idx = changeIndices[s];
            if (last.get(idx) === s) {
                heapPush(h, -nums[idx - 1]);
                const top = -h[0];
                if (top > 1) { saved += top; heapPop(h); }
                else { heapPop(h); free++; }
            } else {
                free++;
            }
        }
        return free >= (totalNums - saved) + n;
    }
    let lo = 1, hi = m, ans = -1;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (feasible(mid)) { ans = mid; hi = mid - 1; }
        else lo = mid + 1;
    }
    return ans;
};
